children.data:
*, *::before, *::after { box-sizing: border-box; }
:root { --color-primary: #005fcc; --color-accent: #e63946; --color-bg-subtle: #f0f0f0; --spacing-md: 1em; --radius: 4px; }
body { font-family: serif; margin: 2em auto; max-width: 800px; color: #111; background: #fff; }
h1 { font-size: 2em; } h2 { font-size: 1.5em; margin-top: 1.5em; border-bottom: 1px solid #ccc; } h3 { font-size: 1.2em; }
p { line-height: 1.6; }
a { color: #00e; } a:visited { color: #551a8b; }
code { background: #f0f0f0; padding: 0.1em 0.3em; font-family: monospace; }
pre { background: #f0f0f0; padding: 1em; overflow-x: auto; }
pre code { background: none; padding: 0; }
blockquote { border-left: 4px solid #ccc; margin-left: 0; padding-left: 1em; color: #555; }
table { border-collapse: collapse; width: 100%; }
th, td { border: 1px solid #ccc; padding: 0.5em 1em; text-align: left; }
th { background: #f0f0f0; }
ul, ol { line-height: 1.8; }
hr { border: none; border-top: 1px solid #ccc; margin: 2em 0; }
.box { border: 1px solid #aaa; padding: 1em; margin: 1em 0; }
a:hover { color: var(--color-accent); }
a:focus { outline: 2px solid var(--color-primary); outline-offset: 2px; }
input:focus, textarea:focus, select:focus { outline: 2px solid var(--color-primary); }
.pseudo-list li:first-child { font-weight: bold; }
.pseudo-list li:last-child { font-style: italic; }
.pseudo-list li:nth-child(even) { background: var(--color-bg-subtle); }
.pseudo-list li:not(.excluded) { color: #111; }
.pseudo-list li.excluded { color: #aaa; text-decoration: line-through; }
.pseudo-before::before { content: "\2192 "; color: var(--color-accent); }
.pseudo-after::after { content: " \2190"; color: var(--color-accent); }
.pseudo-first-line::first-line { font-variant: small-caps; letter-spacing: 0.05em; }
.pseudo-first-letter::first-letter { font-size: 2.5em; float: left; line-height: 1; margin-right: 0.1em; color: var(--color-primary); }
.display-inline-block { display: inline-block; width: 80px; height: 40px; background: #cde; border: 1px solid #99b; vertical-align: middle; }
.display-none { display: none; }
.overflow-hidden { overflow: hidden; max-height: 3em; background: #ffd; padding: 0.5em; }
.overflow-scroll { overflow: scroll; max-height: 3em; background: #dff; padding: 0.5em; }
.overflow-auto { overflow: auto; max-height: 3em; background: #fdf; padding: 0.5em; }
.pos-container { position: relative; height: 80px; border: 1px dashed #aaa; margin: 0.5em 0; }
.pos-absolute { position: absolute; top: 8px; right: 8px; background: #fdd; padding: 0.25em 0.5em; }
.pos-sticky-demo { position: sticky; top: 0; background: #fffbe6; border-bottom: 1px solid #ccc; padding: 0.25em 0.5em; }
.z-base { position: relative; z-index: 1; background: #dde; width: 100px; height: 40px; display: inline-block; }
.z-on-top { position: relative; z-index: 10; background: rgba(255,100,100,0.85); width: 80px; height: 40px; display: inline-block; margin-left: -40px; vertical-align: top; }
.opacity-50 { opacity: 0.5; }
.visibility-hidden { visibility: hidden; }
.transition-box { display: inline-block; padding: 0.5em 1em; background: var(--color-primary); color: #fff; border-radius: var(--radius); transition: background 0.3s ease, transform 0.3s ease; cursor: pointer; }
.transition-box:hover { background: var(--color-accent); transform: scale(1.05); }
.transform-demo { display: inline-block; padding: 0.5em 1em; background: #eef; border: 1px solid #aac; transform: rotate(-2deg) translateX(8px); }
.calc-width { width: calc(100% - 4em); background: #efe; padding: 0.5em; }
.clamp-text { font-size: clamp(0.85rem, 2vw, 1.25rem); background: #fef; padding: 0.5em; }
.flex-container { display: flex; gap: 0.5em; align-items: center; flex-wrap: wrap; background: #f5f5f5; padding: 0.5em; }
.flex-item { flex: 1 1 80px; background: var(--color-primary); color: #fff; padding: 0.5em; text-align: center; border-radius: var(--radius); }
.flex-item.grow2 { flex-grow: 2; background: var(--color-accent); }
.flex-col { display: flex; flex-direction: column; gap: 0.25em; }
.grid-container { display: grid; grid-template-columns: repeat(3, 1fr); gap: 0.5em; }
.grid-item { background: #e8eaf6; border: 1px solid #c5cae9; padding: 0.5em; text-align: center; }
.grid-item.span2 { grid-column: span 2; background: #c5cae9; }
.grid-named { display: grid; grid-template-areas: "header header" "sidebar content" "footer footer"; grid-template-columns: 1fr 2fr; gap: 0.5em; }
.area-header { grid-area: header; background: #b2dfdb; padding: 0.5em; text-align: center; }
.area-sidebar { grid-area: sidebar; background: #c8e6c9; padding: 0.5em; }
.area-content { grid-area: content; background: #dcedc8; padding: 0.5em; }
.area-footer { grid-area: footer; background: #b2dfdb; padding: 0.5em; text-align: center; }
@media (max-width: 600px) { .grid-container { grid-template-columns: 1fr; } .flex-item { flex-basis: 100%; } }
@media (prefers-color-scheme: dark) { .dark-note::after { content: " (dark mode active)"; color: #aaa; font-size: 0.85em; } }
@media print { .no-print { display: none; } }

